package telemele.scheduler.model;

import at.ac.tuwien.kr.alpha.intermediate.AstItem;
import java.time.Duration;
import java.util.ArrayList;

public class Activity {
    
    // An Activity can be: Assignment, Decision, Content
    public enum Subtype { Assignment, Decision, Content }
    
    private final AstItem item;
    // for every "reading" the subactivites are:
    // while (there is another page to do) -> choose show/reflection/question
    // "duration per page = duration/pages"
    private final int pages;
    private final Subtype type;
    private Object result = null;
    private final ArrayList<String> TristanTypes = new ArrayList<>();
    
    public Activity(AstItem item, Subtype type) {
        this.item = item;
        TristanTypes.add("Assign");
        TristanTypes.add("Folder");
        TristanTypes.add("Lesson");
        TristanTypes.add("Project");
        TristanTypes.add("Program");
        TristanTypes.add("Assignment");
        TristanTypes.add("TextBook");
        TristanTypes.add("Video");
        TristanTypes.add("Assessment");
        TristanTypes.add("ETEASTVIDEO");
        TristanTypes.add("IFRAME");
        
        this.type = type;
        this.pages = 0;
        if (type == Subtype.Assignment) {
            try {
                this.pages = Integer.parseInt(item.bindingValue);
            } catch (Exception ex) {
                return;
            }
        }
    }

    public AstItem getItem() {
        return item;
    }

    public Object getResult() {
        return result;
    }

    public void setResult(Object result) {
        this.result = result;
    }

    public boolean acceptsResultType(String type) {
        return TristanTypes.contains(type);
    }

    public int getPages() {
        return pages;
    }
    
    static public Duration FIVE_MINUTES = Duration.ofSeconds(300);

    public static Duration getTimePerPage(int pages) {
        return TimeUnit.create(1, TimeUnit.MINUTES, pages, TimeUnit.PAGE, 0)
                .convert(FIVE_MINUTES);
    }

    public int getPageDurationFactor() {
        return this.type == Subtype.Assignment ? pages : 1;
    }

    public Subtype getType() {
        return type;
    }
    
    
}
