package telemele.scheduler.model;

import telemele.scheduler.model.Condition.ConditionType;

import java.io.Serializable;
import java.util.ArrayList;
import java.util.Collections;
import java.util.List;

abstract public class Action implements Serializable {

    protected final List<Condition> preconditions = new ArrayList<>();

    public Action(Condition... conditions) {
        if (conditions != null && conditions.length > 0) {
            for (Condition cond : conditions) {
                this.preconditions.add(cond);
            }
        }
    }

    public boolean fits(Profile profile) {
        if (profile == null || profile.getVersion() == null) {
            return false;
        }
        for (Condition cond : this.preconditions) {
            profile.visitCondition(cond, this);
            if (!cond.fits()) {
                return false;
            }
        }
        return true;
    }

    public final List<Condition> getPreconditions() {
        return Collections.unmodifiableList(preconditions);
    }

    public void addPrecondition(Condition cond) {
        preconditions.add(cond);
    }

    public void removePrecondition(Condition cond) {
        preconditions.remove(cond);
    }

    public final List<ProfiledVersionElement> applicableVersions(Profile profile, Profile includedProfile) {
        List<ProfiledVersionElement> elements = new ArrayList<>();
        exploreVersions(this, profile, includedProfile, elements);
        return elements;
    }

    private void exploreVersions(Action action, Profile profile, Profile includedProfile, List<ProfiledVersionElement> elements) {
        if (action != null) {
            profile.visitAction(action);

            if (includedProfile == null || includedProfile.witness(ListVersionsCondition.NAME, ActionCondition.invokeConditionID(action))) {
                for (ProfiledVersionElement version = profile.getVersion(); version != null; version = version.getParent()) {
                    elements.add(version);
                }
            }

            for (Condition cond : preconditions) {
                exploreVersions(null, profile, includedProfile, elements);
            }
        }
    }

